prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?org WHERE {
  ?model a bboExt:Model .
  ?model tai:normalizedId "1cd93309017949fdbebf0f7d7ea50b4a" .
  OPTIONAL { ?model bbo:name ?modelName . }
  ?model tai:belongsTo ?org .
  OPTIONAL { ?org rdfs:label ?orgName . }
}

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?origId ?normId WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  OPTIONAL { ?model bbo:id ?modelId . }
}
LIMIT 10

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?origId ?normId WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  FILTER(?origId = "1cd93309017949fdbebf0f7d7ea50b4a" || ?normId = "1cd93309017949fdbebf0f7d7ea50b4a")
}

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
# Let's check if there are participantMultiplicity elements that might define the second participant
SELECT ?task ?taskName ?mult ?min ?max ?partRef WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "1cd93309017949fdbebf0f7d7ea50b4a" .
  ?model tai:belongsTo ?org .
  ?def tai:belongsTo ?model .
  ?choreo tai:belongsTo ?def .
  ?task a bboExt:ChoreographyTask .
  ?task tai:belongsTo ?choreo .
  OPTIONAL { ?task bbo:name ?taskName . }
  OPTIONAL { ?task bboExt:participantMultiplicity ?mult . }
  OPTIONAL { ?mult bboExt:minimum ?min . }
  OPTIONAL { ?mult bboExt:maximum ?max . }
  OPTIONAL { ?mult bbo:participantRef ?partRef . }
}
LIMIT 20
